1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge case: empty policy ---
6	  it("quote with empty item list returns premium 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums for single main items (with 5 G fee, newcomer 10% first-insurance) ---
15	  // Note: a single-item quote for a newcomer with 0 years is the minimal sensible scenario.
16	  // To keep the simplest tests truly simple, we test the base-premium examples through
17	  // long-standing-customer follow-up scenarios where only the base + fee apply.
18	  // We test base premiums first via the spec examples about building blocks (which are
19	  // explicitly described as "base premiums"). So we start there.
20	
21	  // --- Building block of 3 alike components (base premium examples from spec) ---
22	  it("2 runes have base premium 50 G (2 x 25 G, no block)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 55 }] });
28	  });
29	  it("3 runes have base premium 60 G (block applies)", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 65 }] });
35	  });
36	  it("4 runes have base premium 100 G (no block — block requires exactly 3)", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 105 }] });
42	  });
43	  it("7 runes have base premium 175 G (no block possible across 7)", () => {
44	    const result = runScenario({
45	      customer: { yearsWithMHPCO: 0 },
46	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
47	    });
48	    expect(result).toEqual({ results: [{ premium: 180 }] });
49	  });
50	
51	  // --- "Alike" components clarification (❓ same type, not same family) ---
52	  it("2 runes + 1 moonstone have base premium 75 G (no block — different types)", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
56	    });
57	    expect(result).toEqual({ results: [{ premium: 80 }] });
58	  });
59	  it.todo("3 runes + 3 moonstones have base premium 120 G (two separate blocks of 3 same type)");
60	
61	  // --- Modifier thresholds ---
62	  it.todo("customer with exactly 2 years receives loyalty discount");
63	  it.todo("sword with exactly enchantment 5 gets high-enchantment surcharge");
64	  it.todo("sword with enchantment 4 does NOT get high-enchantment surcharge");
65	  it.todo("cursed sword with enchantment 5 gets both curse and high-enchantment surcharges");
66	
67	  // --- Rounding rules ---
68	  it.todo("premium calculation yielding 197.5 G rounds UP to 198 G (MHPCO favor)");
69	  it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 G (MHPCO favor)");
70	  it.todo("intermediate amounts are kept as fractions; only the final premium/payout is rounded");
71	
72	  // --- Modifier scope on multi-item policies (❓ item-specific vs policy-wide) ---
73	  it.todo("policy with cursed sword (100 G base) + plain amulet (60 G base) has policy base 160 G; curse adds 50 G (50% of sword base, not policy total) → 210 G before further modifiers and fee");
74	  it.todo("item-specific modifiers (cursed, high enchantment) apply to the affected item's base premium");
75	  it.todo("policy-wide modifiers (loyalty, first insurance, follow-up contract) apply to the policy base premium");
76	  it.todo("processing fee is added at the very end after all other modifiers");
77	
78	  // --- Integration example 1: Newcomer with cursed sword ---
79	  it.todo("newcomer (0 years, no previous contract) with cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-insurance = 160 + 5 fee)");
80	
81	  // --- Integration example 2: Long-standing customer's second contract ---
82	  it.todo("long-standing customer (3 years, 2nd quote) with cursed sword (steel, ench 7) → premium 160 G (100 base + 50 curse + 30 high-ench - 20 loyalty + 10 first-insurance - 15 follow-up = 155 + 5 fee)");
83	  it.todo("first-insurance surcharge applies to every item in every quote, regardless of customer history (❓ clarification)");
84	
85	  // --- Claim processing: standard reimbursement (no special clauses) ---
86	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
87	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (full minus 100 deductible; no special clause)");
88	
89	  // --- Claim processing: deductible per damage event ---
90	  it.todo("dragon attack damages insured sword (500 G) and amulet (300 G) → payout 600 G (100 deductible per item)");
91	
92	  // --- Enchantment threshold vs. dragon material ---
93	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause: 50%, then deductible)");
94	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon material, then deductible: 500 - 100)");
95	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause: full, then deductible: 800 - 100)");
96	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause: 50%, then deductible: 500 - 100)");
97	
98	  // --- Multiple items of the same type (❓ two swords) ---
99	  it.todo("policy covers two swords → insurance sum 2000 G (= 2 x 1000)");
100	  it.todo("dragon attack damages both swords; each damages entry treated as separate damage with own deductible");
101	  it.todo("damages array contains more entries of a type than the policy covers → whole claim rejected (non-zero exit)");
102	
103	  // --- Edge cases ---
104	  it.todo("quote includes item with unknown type (e.g. broomstick) → non-zero exit, error on stderr, no results on stdout");
105	  it.todo("claim references damage entry for an item not part of the policy (e.g. amulet damaged when only sword insured) → non-zero exit, error on stderr");
106	  it.todo("claim references damage entry with unknown item type → non-zero exit, error on stderr");
107	  it.todo("claim contains a damage entry with amount -200 → non-zero exit, error on stderr");
108	
109	  // --- CLI integration (reads JSON from stdin, writes results to stdout) ---
110	  it.todo("CLI scenario with a quote step writes {results: [{premium: N}]} to stdout");
111	  it.todo("CLI scenario with quote followed by claim referencing policy by zero-based step index produces results in same order as steps");
112	});
