1	const PROCESSING_FEE = 5;
2	const RUNE_BASE_PREMIUM = 25;
3	const BLOCK_OF_THREE_DISCOUNT = 15;
4	
5	type Scenario = { steps: { op: string; items: unknown[] }[] };
6	
7	export function runScenario(scenario: unknown): unknown {
8	  const items = (scenario as Scenario).steps[0].items;
9	  const naturalBase = items.length * RUNE_BASE_PREMIUM;
10	  const blockDiscount = items.length === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
11	  const basePremium = naturalBase - blockDiscount;
12	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
13	}
